// Prepare real-time data for cloud synchronization
const moment = require('moment');

// Get latest system data
const pvData = global.get('pv_data') || {};
const gensetData = global.get('genset_data') || {};
const gridData = global.get('power_meter_data') || {};
const systemState = global.get('system_state') || {};

// Create real-time data package
const realTimeData = {
    timestamp: moment().toISOString(),
    site_id: 'PV_SITE_001', // Configure site identifier
    data: {
        pv: {
            power: pvData.ac_power || 0,
            voltage: pvData.dc_voltage || 0,
