            efficiency: pvData.efficiency || 0,
            temperature: pvData.temperature || 0,
            status: pvData.status || 0
        },
        genset: {
            power: gensetData.ac_power || 0,
            running: gensetData.running || false,
            fuel_level: gensetData.fuel_level || 0,
            engine_temp: gensetData.engine_temp || 0,
